import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.D46keoNO.js";const p=JSON.parse('{"title":"Translation Services","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/services.md","filePath":"en/guide/services.md","lastUpdated":1784107251000}'),r={name:"en/guide/services.md"};function n(l,e,s,c,d,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="translation-services" tabindex="-1">Translation Services <a class="header-anchor" href="#translation-services" aria-label="Permalink to &quot;Translation Services&quot;">​</a></h1><h2 id="service-list" tabindex="-1">Service List <a class="header-anchor" href="#service-list" aria-label="Permalink to &quot;Service List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Authentication</th><th>Cost</th><th>Description</th></tr></thead><tbody><tr><td>Pinyin</td><td>Zero config</td><td>Free</td><td>Fallback service, supports CJK character pinyin conversion</td></tr><tr><td>ChatGPT / OpenAI</td><td>API Key</td><td>Pay per use</td><td>Custom baseUrl/model, compatible with third-party APIs</td></tr><tr><td>Google Translation</td><td>API Key</td><td>Pay per use</td><td>Official Cloud Translation API, requires Google Cloud API Key</td></tr><tr><td>Bing / Azure Translator</td><td>API Key</td><td>Pay per use</td><td>Requires Azure account, supports custom region</td></tr><tr><td>DeepLX</td><td>Local deployment</td><td>Free</td><td>Auto health check, supports custom service URL</td></tr><tr><td>Baidu Translation</td><td>APP_ID + Key</td><td>Pay per use</td><td>Requires Baidu Translation account</td></tr><tr><td>Tencent Translation</td><td>SecretId + SecretKey</td><td>Pay per use</td><td>Supports custom region (default: ap-guangzhou)</td></tr></tbody></table><h2 id="api-key-acquisition" tabindex="-1">API Key Acquisition <a class="header-anchor" href="#api-key-acquisition" aria-label="Permalink to &quot;API Key Acquisition&quot;">​</a></h2><h3 id="openai" tabindex="-1">OpenAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ol><li>Visit <a href="https://platform.openai.com/" target="_blank" rel="noreferrer">OpenAI Platform</a></li><li>Register/Login</li><li>Go to <a href="https://platform.openai.com/api-keys" target="_blank" rel="noreferrer">API Keys page</a></li><li>Click &quot;Create new secret key&quot;</li><li>Copy the generated API Key (format: <code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code>)</li><li>(Optional) Customize <code>baseUrl</code> to use third-party OpenAI-compatible APIs</li><li>(Optional) Customize <code>model</code> to use other models (default: <code>gpt-3.5-turbo</code>)</li></ol><h3 id="google-translation" tabindex="-1">Google Translation <a class="header-anchor" href="#google-translation" aria-label="Permalink to &quot;Google Translation&quot;">​</a></h3><ol><li>Visit <a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">Google Cloud Console</a></li><li>Register/Login and create a project</li><li>Enable <a href="https://console.cloud.google.com/apis/library/translate.googleapis.com" target="_blank" rel="noreferrer">Cloud Translation API</a></li><li>Go to &quot;APIs &amp; Services → Credentials&quot; and create an API Key</li><li>Copy the API Key into the plugin configuration</li></ol><h3 id="baidu-translation" tabindex="-1">Baidu Translation <a class="header-anchor" href="#baidu-translation" aria-label="Permalink to &quot;Baidu Translation&quot;">​</a></h3><ol><li>Visit <a href="https://fanyi-api.baidu.com/" target="_blank" rel="noreferrer">Baidu Translation Open Platform</a></li><li>Register/Login</li><li>Go to <a href="https://fanyi-api.baidu.com/aitrans" target="_blank" rel="noreferrer">Console</a></li><li>Enable General Translation API service</li><li>Get APP_ID and Secret Key</li></ol><h3 id="tencent-translation" tabindex="-1">Tencent Translation <a class="header-anchor" href="#tencent-translation" aria-label="Permalink to &quot;Tencent Translation&quot;">​</a></h3><ol><li>Visit <a href="https://console.cloud.tencent.com/" target="_blank" rel="noreferrer">Tencent Cloud</a></li><li>Register/Login</li><li>Enable <a href="https://console.cloud.tencent.com/tmt" target="_blank" rel="noreferrer">Machine Translation</a> service</li><li>Go to <a href="https://console.cloud.tencent.com/cam/capi" target="_blank" rel="noreferrer">API Key Management</a></li><li>Get SecretId and SecretKey</li><li>(Optional) Customize <code>region</code> to use a different region (default: <code>ap-guangzhou</code>)</li></ol><h3 id="bing-azure-translator" tabindex="-1">Bing / Azure Translator <a class="header-anchor" href="#bing-azure-translator" aria-label="Permalink to &quot;Bing / Azure Translator&quot;">​</a></h3><ol><li>Visit <a href="https://portal.azure.com/" target="_blank" rel="noreferrer">Azure Portal</a></li><li>Register/Login</li><li>Create <a href="https://portal.azure.com/#create/Microsoft.CognitiveServicesMultiService" target="_blank" rel="noreferrer">Translator</a> resource</li><li>Go to resource → &quot;Keys and Endpoint&quot;</li><li>Copy API Key and Region</li></ol><h3 id="deeplx" tabindex="-1">DeepLX <a class="header-anchor" href="#deeplx" aria-label="Permalink to &quot;DeepLX&quot;">​</a></h3><ol><li>Visit <a href="https://deeplx.owo.network/" target="_blank" rel="noreferrer">DeepLX</a> or <a href="https://github.com/OwO-Network/DeepLX" target="_blank" rel="noreferrer">DeepLX GitHub</a></li><li>Follow instructions for local deployment</li><li>Default URL: <code>http://127.0.0.1:1188</code></li><li>Auto health check on startup (60s cache) for accurate availability detection</li><li>Supports custom <code>baseUrl</code> configuration</li><li>No additional configuration needed</li></ol><h2 id="switching-methods" tabindex="-1">Switching Methods <a class="header-anchor" href="#switching-methods" aria-label="Permalink to &quot;Switching Methods&quot;">​</a></h2><h3 id="shortcut-key" tabindex="-1">Shortcut Key <a class="header-anchor" href="#shortcut-key" aria-label="Permalink to &quot;Shortcut Key&quot;">​</a></h3><p>Press <code>Alt+Shift+S</code> to quickly switch translation service.</p><h3 id="command-palette" tabindex="-1">Command Palette <a class="header-anchor" href="#command-palette" aria-label="Permalink to &quot;Command Palette&quot;">​</a></h3><ol><li>Press <code>Ctrl+Shift+P</code></li><li>Type &quot;Switch Translation Service&quot;</li><li>Select the service to use</li></ol><h2 id="service-features" tabindex="-1">Service Features <a class="header-anchor" href="#service-features" aria-label="Permalink to &quot;Service Features&quot;">​</a></h2><h3 id="pinyin" tabindex="-1">Pinyin <a class="header-anchor" href="#pinyin" aria-label="Permalink to &quot;Pinyin&quot;">​</a></h3><ul><li><strong>Pros</strong>: Zero config, supports CJK character pinyin conversion</li><li><strong>Cons</strong>: Lower translation quality than online services</li><li><strong>Recommendation</strong>: As fallback service</li></ul><h3 id="google-translation-1" tabindex="-1">Google Translation <a class="header-anchor" href="#google-translation-1" aria-label="Permalink to &quot;Google Translation&quot;">​</a></h3><ul><li><strong>Pros</strong>: Official API, stable quality, no captcha / IP ban risk</li><li><strong>Cons</strong>: Requires Google Cloud account and API Key, pay per use</li><li><strong>Recommendation</strong>: Use when stable Google translation quality is needed</li></ul><h3 id="openai-1" tabindex="-1">OpenAI <a class="header-anchor" href="#openai-1" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ul><li><strong>Pros</strong>: High translation quality, supports custom baseUrl/model</li><li><strong>Cons</strong>: Requires API Key, pay per use</li><li><strong>Recommendation</strong>: Use when high quality translation is needed, compatible with third-party APIs</li></ul><h3 id="baidu-translation-1" tabindex="-1">Baidu Translation <a class="header-anchor" href="#baidu-translation-1" aria-label="Permalink to &quot;Baidu Translation&quot;">​</a></h3><ul><li><strong>Pros</strong>: Domestic service, fast speed</li><li><strong>Cons</strong>: Requires account registration</li><li><strong>Recommendation</strong>: Recommended for domestic users</li></ul><h3 id="deeplx-1" tabindex="-1">DeepLX <a class="header-anchor" href="#deeplx-1" aria-label="Permalink to &quot;DeepLX&quot;">​</a></h3><ul><li><strong>Pros</strong>: Local deployment, free, auto health check</li><li><strong>Cons</strong>: Requires local service deployment</li><li><strong>Recommendation</strong>: Use when privacy or free service is important</li></ul><h3 id="tencent-translation-1" tabindex="-1">Tencent Translation <a class="header-anchor" href="#tencent-translation-1" aria-label="Permalink to &quot;Tencent Translation&quot;">​</a></h3><ul><li><strong>Pros</strong>: Domestic service, fast speed, supports custom region</li><li><strong>Cons</strong>: Requires Tencent Cloud account</li><li><strong>Recommendation</strong>: Recommended for domestic users</li></ul><h2 id="service-degradation" tabindex="-1">Service Degradation <a class="header-anchor" href="#service-degradation" aria-label="Permalink to &quot;Service Degradation&quot;">​</a></h2><p>When translation service fails, the plugin automatically degrades by priority:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Current service failed → Degrade to next service → All services failed → Degrade to pinyin</span></span></code></pre></div><p>All translation services have <strong>10-second timeout control</strong>, automatically degrading to the next service on timeout. Global translation timeout is also 10 seconds, after which it automatically degrades to pinyin conversion.</p><h2 id="auto-language-detection" tabindex="-1">Auto Language Detection <a class="header-anchor" href="#auto-language-detection" aria-label="Permalink to &quot;Auto Language Detection&quot;">​</a></h2><p>All translation services support auto language detection, capable of translating:</p><ul><li>Chinese</li><li>Japanese</li><li>Korean</li><li>Russian</li><li>Any other non-English characters</li></ul>',41)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
